?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover,user-scalable=no"><meta name="theme-color" content="#050817"><title>Bit Runner | Beyond Games</title><meta name="description" content="Run through Beyond OS, collect bit$ and dodge security viruses in the original Bit Runner browser game."><link rel="stylesheet" href="<?=e(beyond_url('assets/css/bos-21.css'))?>"></head><body class="bos-page runner-page">
<main class="runner-shell">
  <header class="runner-header"><a href="/beyond-games/">← Beyond Games</a><div><b>BIT RUNNER</b><span>by Beyond Games</span></div><button id="soundToggle" type="button" aria-pressed="true">Sound: On</button></header>
  <section class="game-wrap">
    <div class="game-hud"><span>DISTANCE <b id="distance">0m</b></span><span>BITS <b id="bits">0</b></span><span>SCORE <b id="score">0</b></span><span>BEST <b id="best">0</b></span></div>
    <canvas id="game" width="960" height="540" aria-label="Bit Runner game area"></canvas>
    <div class="game-overlay" id="overlay"><div class="overlay-logo">B<span>⚡</span></div><span class="eyebrow">BEYOND OS IS UNDER ATTACK</span><h1 id="overlayTitle">Bit Runner</h1><p id="overlayText">Jump over security viruses, recover lost bit$ and keep the system online.</p><div class="control-help"><span>SPACE / ↑ / TAP<br><b>Jump</b></span><span>↓ / SWIPE DOWN<br><b>Slide</b></span><span>P<br><b>Pause</b></span></div><button id="startGame" type="button">Start run</button><small>Free original browser game · No purchase necessary</small></div>
    <div class="touch-controls"><button id="slideButton" type="button">↓ Slide</button><button id="jumpButton" type="button">↑ Jump</button></div>
  </section>
  <section class="runner-lower"><article><span class="bos-kicker">Achievements</span><h2>System recovery badges</h2><div class="achievement-grid" id="achievements"></div></article><aside><span class="bos-kicker">Daily reward guardrail</span><h2><b id="demoRewards">0</b> / 100 demo bit$</h2><p>Prototype rewards are local demo points. A future Beyond ID connection will require signed-in, server-verified achievements with a strict daily cap.</p><button type="button" id="resetSave">Reset local progress</button></aside></section>
</main>
<script>
(()=>{
const canvas=document.getElementById('game'),ctx=canvas.getContext('2d'),overlay=document.getElementById('overlay'),startBtn=document.getElementById('startGame');
const ui={distance:document.getElementById('distance'),bits:document.getElementById('bits'),score:document.getElementById('score'),best:document.getElementById('best'),rewards:document.getElementById('demoRewards'),achievements:document.getElementById('achievements')};
const storeKey='beyond-games-bit-runner-v1',today=new Date().toISOString().slice(0,10);let saved=JSON.parse(localStorage.getItem(storeKey)||'null')||{best:0,achievements:{},rewardDate:today,rewards:0};if(saved.rewardDate!==today){saved.rewardDate=today;saved.rewards=0}ui.best.textContent=saved.best;ui.rewards.textContent=saved.rewards;
const badgeDefs=[['first-run','Boot Sequence','Start your first run',10],['distance-100','Uplink','Reach 100 metres',15],['bits-10','Data Recovery','Collect 10 bit$',20],['score-1000','System Guardian','Score 1,000 points',25]];
let state='ready',last=0,t=0,speed=330,distance=0,bits=0,score=0,spawnClock=0,coinClock=0,shake=0,sound=true,padJump=false,padSlide=false;
const player={x:150,y:398,w:52,h:72,vy:0,onGround:true,sliding:false},obstacles=[],coins=[],particles=[],ground=470;
function save(){localStorage.setItem(storeKey,JSON.stringify(saved))}
function renderBadges(){ui.achievements.innerHTML=badgeDefs.map(([id,name,desc,reward])=>'<div class="achievement '+(saved.achievements[id]?'earned':'')+'"><span>'+(saved.achievements[id]?'✓':'◇')+'</span><div><b>'+name+'</b><small>'+desc+' · '+reward+' demo bit$</small></div></div>').join('')}
function unlock(id){if(saved.achievements[id])return;saved.achievements[id]=true;const def=badgeDefs.find(x=>x[0]===id),room=Math.max(0,100-saved.rewards),award=Math.min(def[3],room);saved.rewards+=award;ui.rewards.textContent=saved.rewards;save();renderBadges();toast(def[1]+(award?' · +'+award+' demo bit$':''));tone(760,.12)}
function toast(text){const el=document.createElement('div');el.className='game-toast';el.textContent=text;document.querySelector('.game-wrap').appendChild(el);setTimeout(()=>el.remove(),2500)}
function tone(freq,dur){if(!sound)return;try{const ac=tone.ac||(tone.ac=new(window.AudioContext||window.webkitAudioContext)()),o=ac.createOscillator(),g=ac.createGain();o.frequency.value=freq;o.type='square';g.gain.setValueAtTime(.045,ac.currentTime);g.gain.exponentialRampToValueAtTime(.001,ac.currentTime+dur);o.connect(g);g.connect(ac.destination);o.start();o.stop(ac.currentTime+dur)}catch(e){}}
function reset(){t=0;speed=330;distance=0;bits=0;score=0;spawnClock=.8;coinClock=.5;obstacles.length=coins.length=particles.length=0;Object.assign(player,{y:ground-72,vy:0,onGround:true,sliding:false,h:72});updateUi()}
function start(){reset();state='playing';overlay.classList.add('hidden');unlock('first-run');last=performance.now();requestAnimationFrame(loop)}
function jump(){if(state==='ready'||state==='over'){start();return}if(state!=='playing'||!player.onGround)return;player.sliding=false;player.h=72;player.y=ground-player.h;player.vy=-720;player.onGround=false;tone(390,.08)}
function slide(on=true){if(state!=='playing'||!player.onGround)return;player.sliding=on;player.h=on?42:72;player.y=ground-player.h}
function pause(){if(state==='playing'){state='paused';showOverlay('Paused','Take a breath. The system will wait.','Resume run')}else if(state==='paused'){state='playing';overlay.classList.add('hidden');last=performance.now();requestAnimationFrame(loop)}}
function showOverlay(title,text,button){document.getElementById('overlayTitle').textContent=title;document.getElementById('overlayText').textContent=text;startBtn.textContent=button;overlay.classList.remove('hidden')}
function gameOver(){state='over';tone(95,.35);saved.best=Math.max(saved.best,Math.floor(score));ui.best.textContent=saved.best;save();showOverlay('Run interrupted','You recovered '+bits+' bit$ and travelled '+Math.floor(distance)+'m. The system needs another run.','Run again')}
function spawnObstacle(){const tall=Math.random()>.48;obstacles.push({x:1000,y:ground-(tall?64:38),w:tall?46:70,h:tall?64:38,pulse:Math.random()*6.2});spawnClock=Math.max(.65,1.45-speed/850)+Math.random()*.55}
function spawnCoins(){const count=3+Math.floor(Math.random()*3),high=Math.random()>.45;for(let i=0;i<count;i++)coins.push({x:1000+i*50,y:high?ground-145-Math.sin(i/(count-1)*Math.PI)*55:ground-82,r:12,spin:Math.random()*6.2});coinClock=1.5+Math.random()*1.8}
function hit(a,b){return a.x<b.x+b.w&&a.x+a.w>b.x&&a.y<b.y+b.h&&a.y+a.h>b.y}
function update(dt){t+=dt;speed=Math.min(620,330+t*7);distance+=speed*dt/18;score+=speed*dt/10;spawnClock-=dt;coinClock-=dt;if(spawnClock<=0)spawnObstacle();if(coinClock<=0)spawnCoins();
  player.vy+=1900*dt;player.y+=player.vy*dt;if(player.y+player.h>=ground){player.y=ground-player.h;player.vy=0;player.onGround=true}
  for(const o of obstacles)o.x-=speed*dt;for(const c of coins){c.x-=speed*dt;c.spin+=dt*7}for(const p of particles){p.x+=p.vx*dt;p.y+=p.vy*dt;p.life-=dt}
  while(obstacles[0]&&obstacles[0].x<-100)obstacles.shift();while(coins[0]&&coins[0].x<-50)coins.shift();
  for(const o of obstacles)if(hit(player,o)){shake=12;gameOver();return}
  for(let i=coins.length-1;i>=0;i--){const c=coins[i];if(hit(player,{x:c.x-c.r,y:c.y-c.r,w:c.r*2,h:c.r*2})){coins.splice(i,1);bits++;score+=100;tone(620+bits*10,.07);for(let n=0;n<8;n++)particles.push({x:c.x,y:c.y,vx:(Math.random()-.5)*180,vy:(Math.random()-.5)*180,life:.55})}}
  particles.splice(0,particles.length,...particles.filter(p=>p.life>0));if(distance>=100)unlock('distance-100');if(bits>=10)unlock('bits-10');if(score>=1000)unlock('score-1000');updateUi()}
function updateUi(){ui.distance.textContent=Math.floor(distance)+'m';ui.bits.textContent=bits;ui.score.textContent=Math.floor(score)}
function draw(){ctx.save();if(shake>0){ctx.translate((Math.random()-.5)*shake,(Math.random()-.5)*shake);shake*=.82}const g=ctx.createLinearGradient(0,0,0,540);g.addColorStop(0,'#080b21');g.addColorStop(.6,'#151044');g.addColorStop(1,'#081628');ctx.fillStyle=g;ctx.fillRect(0,0,960,540);
  ctx.globalAlpha=.55;ctx.strokeStyle='#6749c8';ctx.lineWidth=1;const off=(distance*9)%60;for(let x=-off;x<960;x+=60){ctx.beginPath();ctx.moveTo(x,ground);ctx.lineTo(480+(x-480)*1.8,540);ctx.stroke()}for(let y=ground;y<540;y+=22){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(960,y);ctx.stroke()}ctx.globalAlpha=1;
  for(let i=0;i<28;i++){const x=(i*173-distance*1.8)%1000,y=40+(i*67)%250;ctx.fillStyle=i%3?'#4debd1':'#9b63ff';ctx.globalAlpha=.25+(i%5)*.1;ctx.fillRect(x,y,2+(i%2)*3,2+(i%2)*3)}ctx.globalAlpha=1;
  ctx.fillStyle='#22184f';ctx.fillRect(0,ground,960,70);ctx.fillStyle='#54f1da';ctx.fillRect(0,ground,960,4);
  for(const c of coins){ctx.save();ctx.translate(c.x,c.y);ctx.scale(Math.abs(Math.cos(c.spin))+.12,1);ctx.beginPath();ctx.arc(0,0,c.r,0,Math.PI*2);ctx.fillStyle='#f4cf4f';ctx.shadowColor='#ffe675';ctx.shadowBlur=18;ctx.fill();ctx.fillStyle='#5b3e12';ctx.font='bold 14px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('b',0,1);ctx.restore()}
  for(const o of obstacles){ctx.save();ctx.translate(o.x,o.y);ctx.shadowColor='#ff3c8d';ctx.shadowBlur=12+Math.sin(t*7+o.pulse)*5;ctx.fillStyle='#461339';ctx.strokeStyle='#ff4e9d';ctx.lineWidth=3;ctx.fillRect(0,0,o.w,o.h);ctx.strokeRect(0,0,o.w,o.h);ctx.fillStyle='#ff8bc3';ctx.font='bold 23px sans-serif';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('×',o.w/2,o.h/2);ctx.restore()}
  ctx.save();ctx.translate(player.x,player.y);ctx.shadowColor='#8f66ff';ctx.shadowBlur=22;ctx.fillStyle='#f7f7ff';ctx.fillRect(10,0,32,28);ctx.fillStyle='#7355ff';ctx.fillRect(4,26,44,player.h-27);ctx.fillStyle='#54f1da';ctx.fillRect(player.sliding?42:39,10,16,9);if(!player.sliding){const leg=Math.sin(t*16)*10;ctx.strokeStyle='#f7f7ff';ctx.lineWidth=9;ctx.beginPath();ctx.moveTo(17,player.h-4);ctx.lineTo(12+leg,player.h+8);ctx.moveTo(36,player.h-4);ctx.lineTo(40-leg,player.h+8);ctx.stroke()}ctx.restore();
  for(const p of particles){ctx.globalAlpha=Math.max(0,p.life*2);ctx.fillStyle='#ffe56c';ctx.fillRect(p.x,p.y,5,5)}ctx.globalAlpha=1;ctx.restore()}
function pollGamepad(){const gp=navigator.getGamepads&&navigator.getGamepads()[0];if(!gp)return;const nextJump=!!((gp.buttons[0]&&gp.buttons[0].pressed)||(gp.buttons[12]&&gp.buttons[12].pressed)),nextSlide=!!((gp.buttons[1]&&gp.buttons[1].pressed)||(gp.buttons[13]&&gp.buttons[13].pressed));if(nextJump&&!padJump)jump();if(nextSlide!==padSlide)slide(nextSlide);padJump=nextJump;padSlide=nextSlide}
function loop(now){if(state!=='playing')return;const dt=Math.min(.033,(now-last)/1000);last=now;pollGamepad();update(dt);draw();if(state==='playing')requestAnimationFrame(loop)}
window.addEventListener('keydown',e=>{if(['Space','ArrowUp','ArrowDown'].includes(e.code))e.preventDefault();if(e.code==='Space'||e.code==='ArrowUp')jump();if(e.code==='ArrowDown')slide(true);if(e.code==='KeyP')pause()});window.addEventListener('keyup',e=>{if(e.code==='ArrowDown')slide(false)});
document.getElementById('jumpButton').addEventListener('pointerdown',jump);const slideBtn=document.getElementById('slideButton');slideBtn.addEventListener('pointerdown',()=>slide(true));['pointerup','pointercancel','pointerleave'].forEach(x=>slideBtn.addEventListener(x,()=>slide(false)));canvas.addEventListener('pointerdown',jump);startBtn.addEventListener('click',()=>state==='paused'?pause():start());
document.getElementById('soundToggle').addEventListener('click',e=>{sound=!sound;e.currentTarget.textContent='Sound: '+(sound?'On':'Off');e.currentTarget.setAttribute('aria-pressed',String(sound))});document.getElementById('resetSave').addEventListener('click',()=>{if(!confirm('Reset Bit Runner high score, achievements and demo rewards?'))return;saved={best:0,achievements:{},rewardDate:today,rewards:0};save();ui.best.textContent=ui.rewards.textContent='0';renderBadges()});
renderBadges();draw();
})();
</script>
<style>
