e:.72rem;font-weight:1000;letter-spacing:.13em}.game-overlay h1{font-size:clamp(2.4rem,7vw,5rem);margin:3px 0}.game-overlay p{max-width:560px;margin:0;color:#c1c4dd}.control-help{display:flex;gap:8px;margin:18px 0}.control-help span{padding:8px 12px;border:1px solid rgba(255,255,255,.13);border-radius:11px;color:#969bbd;font-size:.65rem}.control-help b{color:white;font-size:.8rem}.game-overlay button{min-width:170px;border:0;border-radius:14px;padding:13px 22px;background:linear-gradient(135deg,#8454ff,#22d8c2);color:white;font:inherit;font-weight:1000;cursor:pointer}.game-overlay small{margin-top:10px;color:#777d9f}.touch-controls{position:absolute;z-index:3;left:14px;right:14px;bottom:14px;display:flex;justify-content:space-between;pointer-events:none}.touch-controls button{pointer-events:auto;min-width:112px;border:1px solid rgba(255,255,255,.2);border-radius:15px;padding:14px;background:rgba(9,12,33,.78);color:white;font:inherit;font-weight:950;backdrop-filter:blur(10px)}.game-toast{position:absolute;z-index:8;left:50%;top:78px;transform:translateX(-50%);padding:11px 16px;border:1px solid #58f1da;border-radius:999px;background:#0a1930;color:#58f1da;font-weight:950;animation:toast 2.5s both}@keyframes toast{0%{opacity:0;transform:translate(-50%,-10px)}15%,75%{opacity:1;transform:translate(-50%,0)}100%{opacity:0;transform:translate(-50%,-10px)}}.runner-lower{display:grid;grid-template-columns:1.4fr .6fr;gap:15px;margin-top:15px}.runner-lower>article,.runner-lower>aside{padding:22px;border:1px solid rgba(255,255,255,.12);border-radius:20px;background:rgba(17,19,48,.74)}.runner-lower h2{margin:.3rem 0 1rem}.achievement-grid{display:grid;grid-template-columns:1fr 1fr;gap:9px}.achievement{display:flex;gap:10px;align-items:center;padding:11px;border:1px solid rgba(255,255,255,.09);border-radius:13px;color:#727899}.achievement>span{display:grid;place-items:center;width:34px;height:34px;border-radius:50%;background:#202446;font-size:1.1rem}.achievement div{display:grid}.achievement small{color:#777d9f}.achievement.earned{border-color:rgba(83,239,211,.35);color:#fff}.achievement.earned>span{background:#1b715f;color:#6bffe6}.runner-lower aside p{color:#a7acc9;line-height:1.55}.runner-lower aside button{border:1px solid rgba(255,255,255,.15);border-radius:10px;padding:9px 11px;background:none;color:#aeb3d0;font-weight:850}.runner-lower aside h2 b{color:#59f2da}
@media(pointer:fine){.touch-controls{opacity:.35}.touch-controls:hover{opacity:1}}@media(max-width:700px){.runner-header{grid-template-columns:1fr auto}.runner-header>div{display:none}.game-hud{gap:12px;justify-content:space-around}.game-overlay{padding:18px}.overlay-logo{width:68px;height:68px;font-size:3.3rem}.control-help span:last-child{display:none}.runner-lower{grid-template-columns:1fr}.achievement-grid{grid-template-columns:1fr}.touch-controls{bottom:8px}.touch-controls button{min-width:98px;padding:10px}.game-overlay p{font-size:.86rem}.game-overlay small{display:none}}@media(max-width:430px){.game-hud{padding:7px 3px}.game-hud span{font-size:.52rem}.game-hud b{font-size:.78rem}.game-overlay h1{font-size:2.2rem}.control-help{margin:9px 0}.overlay-logo{width:54px;height:54px;font-size:2.6rem}.game-overlay .eyebrow{margin-top:8px}.game-overlay button{padding:9px 15px}.touch-controls button{font-size:.75rem}}
</style><?php bos_page_end(); ?>
